module ring_counter(
    input clk,
    input reset,
    output reg [11:0] count);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        count <= 12'b000000000001;
    else
        count <= {count[10:0], count[11]};
end
endmodule
